const { generateImages } = require('/home/node/.n8n/code/insiderbuying/generate-image.js');

const _https = require('https');
const _http = require('http');
const { URL } = require('url');

function fetchFn(urlStr, opts = {}) {
  return new Promise((resolve, reject) => {
    const u = new URL(urlStr);
    const mod = u.protocol === 'https:' ? _https : _http;
    const reqOpts = {
      hostname: u.hostname, port: u.port,
      path: u.pathname + u.search,
      method: opts.method || 'GET',
      headers: opts.headers || {},
    };
    const req = mod.request(reqOpts, (res) => {
      const chunks = [];
      res.on('data', (c) => chunks.push(c));
      res.on('end', () => {
        const body = Buffer.concat(chunks);
        resolve({
          ok: res.statusCode >= 200 && res.statusCode < 300,
          status: res.statusCode,
          json: () => Promise.resolve(JSON.parse(body.toString())),
          text: () => Promise.resolve(body.toString()),
          arrayBuffer: () => Promise.resolve(body.buffer.slice(body.byteOffset, body.byteOffset + body.byteLength)),
        });
      });
    });
    req.on('error', reject);
    if (opts.body) {
      if (Buffer.isBuffer(opts.body)) req.write(opts.body);
      else req.write(typeof opts.body === 'string' ? opts.body : JSON.stringify(opts.body));
    }
    req.end();
  });
}

const input = $input.first().json;
const result = await generateImages(input, {
  fetchFn,
  env: {
    NOCODB_BASE_URL: $env.NOCODB_BASE_URL,
    NOCODB_API_TOKEN: $env.NOCODB_API_TOKEN,
    FAL_KEY: $env.FAL_KEY,
    SCREENSHOT_SERVER_URL: $env.SCREENSHOT_SERVER_URL || 'http://host.docker.internal:3456',
    R2_ACCOUNT_ID: $env.R2_ACCOUNT_ID,
    R2_ACCESS_KEY_ID: $env.R2_ACCESS_KEY_ID,
    R2_SECRET_ACCESS_KEY: $env.R2_SECRET_ACCESS_KEY,
    R2_PUBLIC_URL: $env.R2_PUBLIC_URL,
  },
});

return [{ json: result }];
